import React, { useState, useEffect } from 'react';
import { CSSTransition, TransitionGroup } from 'react-transition-group';
import styled from 'styled-components';
import { navDelay, loaderDelay, trackEvent } from '@utils';
import { usePrefersReducedMotion } from '@hooks';

const StyledHeroSection = styled.section`
  min-height: 100vh;
  padding: 142px 0 34px;

  @media (max-width: 768px) {
    padding: 118px 0 20px;
  }

  .hero-inner {
    display: block;
    width: 100%;
  }

  .hero-copy {
    max-width: 720px;
  }

  @media (max-height: 700px) and (min-width: 700px), (max-width: 360px) {
    height: auto;
    padding-top: var(--nav-height);
  }

  h1 {
    margin: 0 0 20px 4px;
    color: var(--green);
    font-family: var(--font-ui);
    letter-spacing: 0.04em;
    text-transform: uppercase;
    font-size: clamp(var(--fz-sm), 5vw, var(--fz-md));
    font-weight: 600;

    @media (max-width: 480px) {
      margin: 0 0 20px 2px;
    }
  }

  h3 {
    margin-top: 12px;
    margin-bottom: 20px;
    color: var(--dark-slate);
    line-height: 1.06;
  }

  p {
    margin: 0;
    max-width: 58ch;
    font-size: clamp(var(--fz-md), 2.2vw, var(--fz-xl));
    line-height: 1.62;
  }

  .hero-name,
  .hero-title {
    max-width: 15ch;
  }

  .hero-title {
    font-size: clamp(36px, 6.4vw, 62px);
  }

  .email-link {
    ${({ theme }) => theme.mixins.bigButton};
    margin-top: 0;
  }

  .cta-group {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: 14px;
    margin-top: 32px;
  }

  .cta-secondary {
    ${({ theme }) => theme.mixins.smallButton};
    padding: 0.8rem 1.1rem;
  }

  .hero-focus {
    margin-top: 24px;
    color: var(--light-slate);
    font-size: var(--fz-sm);
    line-height: 1.6;
  }

  .focus-list {
    ${({ theme }) => theme.mixins.resetList};
    display: flex;
    flex-wrap: wrap;
    gap: 6px 12px;
  }

  .focus-item {
    position: relative;
    display: inline-flex;
    align-items: center;
    color: var(--dark-slate);
    font-size: var(--fz-sm);
    font-weight: 500;
    white-space: nowrap;
  }

  .focus-item:not(:last-child):after {
    content: '•';
    margin-left: 12px;
    color: var(--light-slate);
    font-weight: 400;
  }
`;

const Hero = () => {
  const [isMounted, setIsMounted] = useState(false);
  const prefersReducedMotion = usePrefersReducedMotion();

  useEffect(() => {
    if (prefersReducedMotion) {
      return;
    }

    const timeout = setTimeout(() => setIsMounted(true), navDelay);
    return () => clearTimeout(timeout);
  }, []);

  const one = <h1>Hi, my name is</h1>;
  const two = <h2 className="big-heading hero-name">Thomas Doan.</h2>;
  const three = <h3 className="big-heading hero-title">I build things for the web.</h3>;
  const four = (
    <>
      <p>
        I am a senior full-stack engineer focused on product quality, performance, and thoughtful user
        experiences. I am currently open to new opportunities where I can help teams ship meaningful outcomes.
      </p>
    </>
  );
  const five = (
    <div className="cta-group">
      <a
        className="email-link"
        href="/resume.pdf"
        target="_blank"
        rel="noopener noreferrer"
        onClick={() =>
          trackEvent({
            category: 'cta',
            action: 'click_view_resume_hero',
            label: 'Hero View Resume',
          })
        }>
        View Resume
      </a>
      <a
        className="cta-secondary"
        href="/#contact"
        onClick={() =>
          trackEvent({
            category: 'cta',
            action: 'click_contact_me_hero',
            label: 'Hero Contact Me',
          })
        }>
        Contact Me
      </a>
    </div>
  );
  const six = (
    <div className="hero-focus" aria-label="Current focus and availability">
      <ul className="focus-list">
        <li className="focus-item">Product-minded execution</li>
        <li className="focus-item">Healthtech, SaaS, and AI products</li>
      </ul>
    </div>
  );

  const items = [one, two, three, four, five, six];

  return (
    <StyledHeroSection>
      <div className="hero-inner">
        <div className="hero-copy">
          {prefersReducedMotion ? (
            <>
              {items.map((item, i) => (
                <div key={i}>{item}</div>
              ))}
            </>
          ) : (
            <TransitionGroup component={null}>
              {isMounted &&
                items.map((item, i) => (
                  <CSSTransition key={i} classNames="fadeup" timeout={loaderDelay}>
                    <div style={{ transitionDelay: `${i + 1}00ms` }}>{item}</div>
                  </CSSTransition>
                ))}
            </TransitionGroup>
          )}
        </div>

      </div>
    </StyledHeroSection>
  );
};

export default Hero;
